'use strict';
flow.set('ma_config', msg.payload);
// Only initialise runtime state on first deploy; preserve values across redeploys
if (flow.get('ma_owner') === undefined) flow.set('ma_owner', null);
if (!flow.get('ma_zones')) flow.set('ma_zones', { a1: false, a2: false, a3: false, ls: false });
if (flow.get('ma_exec_cue') === undefined) flow.set('ma_exec_cue', 1);
if (flow.get('ma_seq_id') === undefined) flow.set('ma_seq_id', 1);
if (flow.get('ma_seq_cue') === undefined) flow.set('ma_seq_cue', 1);
var dgram = require('dgram');
function oscString(str) {
    var len = Buffer.byteLength(str, 'utf8') + 1;
    var padded = Math.ceil(len / 4) * 4;
    var buf = Buffer.alloc(padded, 0);
    buf.write(str, 0, 'utf8');
    return buf;
}
function encodeOscCmd(v) {
    return Buffer.concat([oscString('/cmd'), oscString(',s'), oscString(v)]);
}
function maOscBroadcast(cmdString, targets) {
    return new Promise(function(resolve, reject) {
        var buf = encodeOscCmd(cmdString);
        var socket = dgram.createSocket('udp4');
        if (socket.unref) socket.unref();
        var sent = [], errors = [];
        var remaining = targets.length;
        socket.on('error', function(sockErr) {
            try { socket.close(); } catch(e){}
            reject(sockErr);
        });
        if (remaining === 0) {
            try { socket.close(); } catch(e){}
            resolve({ cmdString: cmdString, sent: sent, errors: errors });
            return;
        }
        var finish = function() {
            try {
                socket.close(function() {
                    if (errors.length === targets.length) reject(new Error(errors.join('; ')));
                    else resolve({ cmdString: cmdString, sent: sent, errors: errors });
                });
            } catch(e) {
                if (errors.length === targets.length) reject(new Error(errors.join('; ')));
                else resolve({ cmdString: cmdString, sent: sent, errors: errors });
            }
        };
        targets.forEach(function(t) {
            socket.send(buf, 0, buf.length, t.port, t.host, function(err) {
                if (err) errors.push(t.host + ':' + t.port + ' - ' + err.message);
                else sent.push(t.host + ':' + t.port);
                if (--remaining === 0) finish();
            });
        });
    });
}
flow.set('ma_broadcast', maOscBroadcast);
return null;

'use strict';
var owner = msg.payload === '' ? null : msg.payload;
flow.set('ma_owner', owner);
msg.payload = { action: 'setOwner', owner: owner, setBy: 'ui' };
msg.topic = 'ma/owner';
return msg;

'use strict';
// Outputs: [sw-all, sw-a1, sw-a2, sw-a3, sw-ls]
// passthru:false on each switch prevents incoming state msgs from re-firing
// output, so updating switches here never creates feedback loops.
var topic = msg.topic;
var val = !!msg.payload;
var zones = flow.get('ma_zones') || { a1: false, a2: false, a3: false, ls: false };
if (topic === 'zone/all') {
    zones.a1 = val;
    zones.a2 = val;
    zones.a3 = val;
    zones.ls = val;
} else {
    var zone = topic.split('/')[1];
    if (zone && Object.prototype.hasOwnProperty.call(zones, zone)) {
        zones[zone] = val;
    }
}
flow.set('ma_zones', zones);
var allOn = zones.a1 && zones.a2 && zones.a3 && zones.ls;
return [
    [{ payload: allOn,    topic: 'zone/all' }],
    [{ payload: zones.a1, topic: 'zone/a1'  }],
    [{ payload: zones.a2, topic: 'zone/a2'  }],
    [{ payload: zones.a3, topic: 'zone/a3'  }],
    [{ payload: zones.ls, topic: 'zone/ls'  }]
];

'use strict';
var cfg = flow.get('ma_config') || {};
var TARGETS = cfg.targets || [
    { host: '10.154.10.103', port: 8000 },
    { host: '10.154.10.104', port: 8000 }
];
var broadcast = flow.get('ma_broadcast');
if (!broadcast) {
    node.error('[MA] Broadcast helper not initialised — redeploy the flow');
    return null;
}
var ZONE_EXECUTOR = cfg.zoneExecutor || {
    a1: '1.101', a2: '1.102', a3: '1.103', ls: '1.104'
};
// UI commands are blocked only when a non-nodered owner holds the gate
var currentOwner = flow.get('ma_owner') || null;
if (currentOwner !== null && currentOwner !== 'nodered') {
    node.warn('[MA] goExecutorCue blocked — current owner: ' + currentOwner);
    node.send([null, { payload: { success: false, blocked: true, action: 'goExecutorCue', owner: currentOwner }, topic: 'ma/blocked' }]);
    return null;
}
function resolveExecutor(zone) {
    return ZONE_EXECUTOR[zone] !== undefined ? ZONE_EXECUTOR[zone] : String(zone);
}
var zones = flow.get('ma_zones') || { a1: false, a2: false, a3: false, ls: false };
var selectedZones = ['a1', 'a2', 'a3', 'ls'].filter(function(z) { return zones[z]; });
if (selectedZones.length === 0) {
    node.warn('[MA] goExecutorCue — no zones selected');
    return null;
}
var cue = flow.get('ma_exec_cue') || 1;
async function execute() {
    var results = [];
    for (var i = 0; i < selectedZones.length; i++) {
        var z = selectedZones[i];
        var cmdString = 'Go+ Executor ' + resolveExecutor(z) + ' Cue ' + cue;
        var result = await broadcast(cmdString, TARGETS);
        results.push({ zone: z, success: result.errors.length === 0, cmdString: result.cmdString, sent: result.sent, errors: result.errors });
    }
    return results;
}
execute()
    .then(function(results) {
        var allSent = results.every(function(r) { return r.errors.length === 0; });
        node.send([{ payload: { action: 'goExecutorCue', zones: selectedZones, cue: cue, success: allSent, results: results }, topic: 'ma/goExecutorCue' }, null]);
    })
    .catch(function(err) {
        node.send([{ payload: { action: 'goExecutorCue', zones: selectedZones, cue: cue, success: false, error: err.message }, topic: 'ma/goExecutorCue' }, null]);
    });
return null;

'use strict';
